#include<bits/stdc++.h>
using namespace std;
int n,m,fa[5000010][21],lg[5000010],d[5000010],lu,lv;
vector<int> mp[5000010],t[5000010],vec[5000010];
int lst[5000010],val[5000010],v[5000010],tim[5000010],k;
void dfs(int x,int f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int dist(int x,int y)
{
    return d[x]+d[y]-d[lca(x,y)]*2;
}
void update(int x,int l,int r,int L,int R,int v)
{
    if(L>R||l>R||L>r)
    {
        return;
    }
    if(L<=l&&r<=R)
    {
        t[x].push_back(v);
        return;
    }
    int mid=(l+r)>>1;
    update(x<<1,l,mid,L,R,v);
    update(x<<1|1,mid+1,r,L,R,v);
}
void solve(int x,int l,int r)
{
    int lstu=lu,lstv=lv;
    for(auto i:t[x])
    {
        if(lu==0)
        {
            lu=i;
            continue;
        }
        if(lv==0)
        {
            lv=i;
            continue;
        }
        int now=dist(lu,lv),nowu=dist(i,lv),nowv=dist(lu,i);
        int p=max({now,nowu,nowv});
        if(nowu==p)
        {
            lu=i;
        }
        else if(nowv==p)
        {
            lv=i;
        }
    }
    if(l==r)
    {
        if(v[l])
        {

        }
        else if(lu==0)
        {
            printf("-1\n");
        }
        else if(lv==0)
        {
            printf("0\n");
        }
        else
        {
            printf("%d\n",dist(lu,lv));
        }
    }
    else
    {
        int mid=(l+r)>>1;
        solve(x<<1,l,mid);
        solve(x<<1|1,mid+1,r);
    }
    lu=lstu;
    lv=lstv;
}
int main()
{
    scanf("%d",&n);
    for(int i=2;i<=n;i++)
    {
        lg[i]=__lg(i);
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    int q;
    scanf("%d",&q);
    int now=1;
    k=q;
    for(int i=1;i<=n;i++)
    {
        lst[i]=1;
    }
    for(int i=1;i<=q;i++)
    {
        char op;
        int x;
        cin>>op;
        if(op=='C')
        {
            v[i]=1;
            scanf("%d",&x);
            if(val[x])
            {
                lst[x]=i;
            }
            else
            {
                update(1,1,q,lst[x],i-1,x);
            }
            val[x]=1-val[x];
        }
        else
        {
            k++;
        }
    }
    for(int i=1;i<=n;i++)if(lst[i]!=q&&val[i]==0)
    {
        update(1,1,q,lst[i],q,i);
    }
    solve(1,1,q);
    return 0;
}
